	@fsc_id int = null,
	@uv_code nvarchar(50) = null,
	@phoi_tructiep bit = 0
)
AS
BEGIN
	IF ISNUMERIC(@veneer_matchinh) = 0
		SET @veneer_matchinh = null
	IF ISNUMERIC(@veneer_matphu) = 0
		SET @veneer_matphu = null

