		SET @uv_matchinh1 = NULL;
	IF @uv_matphu1 = 0
		SET @uv_matphu1 = NULL;
	IF @uv_canhngan1 = 0
		SET @uv_canhngan1 = NULL;
	IF @uv_canhdai1 = 0
		SET @uv_canhdai1 = NULL;

