		  id_nguyenlieu = @id_nguyenlieu,
		  nguyenlieu = @nguyenlieu,
		  dayy_tc = @dayy_tc,
		  rong_tc = @rong_tc,
		  dai_tc = @dai_tc,
		  soluong_tc = @soluong_tc,
		  m3_tc = @m3_tc,
		  dayy_sc = @dayy_sc,
		  rong_sc = @rong_sc,
		  dai_sc = @dai_sc,
		  soluong_sc = @soluong_sc,
		  m3_sc = @m3_sc,
		  ghichu = @ghichu,
		  ngaysua = @ngaysua,
		  nguoisua = @nguoisua,
		  veneer_matchinh = @veneer_matchinh,
		  veneer_matphu = @veneer_matphu,
		  mong1 = @mong1,
		  mong2 = @mong2,
		  veneer_dan_canh = @veneer_dan_canh,
		  uv_canhngan = @uv_canhngan,
		  uv_canhdai = @uv_canhdai,
		  uv_matchinh = @uv_matchinh,
		  uv_matphu = @uv_matphu,
		  veneer_canhdai = @veneer_canhdai,
		  veneer_canhngan = @veneer_canhngan,
		  banve = @banve,
		  fsc_100 = @fsc_100,
		  fsc_mix = @fsc_mix,
		  fsc_cw = @fsc_cw,
		  fsc_recycled = @fsc_recycled,
		  non_fsc = @non_fsc,
		  uv_matchinh1 = @uv_matchinh1,
		  uv_matphu1 = @uv_matphu1,
		  uv_canhngan1 = @uv_canhngan1,
		  uv_canhdai1 = @uv_canhdai1,
		  fsc_id = @fsc_id,
		  uv_code = @uv_code,
		  phoi_tructiep = @phoi_tructiep
	  WHERE masp = @masp AND mact = @mact
	END
	ELSE
	BEGIN
	  -- INSERT
	  INSERT INTO tr_dinhmuc_govan
	  (
		masp,
		mact,
		stt,
		chitiet,
		id_nguyenlieu,
		nguyenlieu,
		dayy_tc,
		rong_tc,
		dai_tc,
		soluong_tc,
		m3_tc,
		dayy_sc,
		rong_sc,
		dai_sc,
		soluong_sc,
		m3_sc,
		ghichu,
		hoanthanh,
		ngaytao,
		nguoitao,
		nguoisua,
		ngaysua,
		veneer_matchinh,
		veneer_matphu,
		mong1,
		mong2,
		veneer_dan_canh,
		uv_canhngan,
		uv_canhdai,
		uv_matchinh,
		uv_matphu,
		veneer_canhdai,
		veneer_canhngan,
		banve,
		fsc_100, fsc_mix, fsc_cw, fsc_recycled, non_fsc, fsc_id,
		uv_matchinh1, uv_matphu1, uv_canhngan1, uv_canhdai1, uv_code,
		phoi_tructiep
	  )
	  VALUES
	  (
		@masp,
		@mact,
		@stt,
		@chitiet,
		@id_nguyenlieu,
		@nguyenlieu,
		@dayy_tc,
		@rong_tc,
		@dai_tc,
		@soluong_tc,
		@m3_tc,
		@dayy_sc,
		@rong_sc,
		@dai_sc,
		@soluong_sc,
		@m3_sc,
		@ghichu,
		1,
		@ngaytao, 
		@nguoitao,
		@nguoisua,
		@ngaysua,
		@veneer_matchinh,
		@veneer_matphu,
		@mong1,
		@mong2,
		@veneer_dan_canh,
		@uv_canhngan,
		@uv_canhdai,
		@uv_matchinh,
		@uv_matphu,
		@veneer_canhdai,
		@veneer_canhngan,
		@banve,
		@fsc_100, @fsc_mix, @fsc_cw, @fsc_recycled, @non_fsc, @fsc_id,
		@uv_matchinh1, @uv_matphu1, @uv_canhngan1, @uv_canhdai1, @uv_code,
		@phoi_tructiep
	  )
	END

